def _cache_salt(self, pred_i: int, demo_set_i: int) -> str:
    # Deterministic given self.rng (seeded upstream) + stable IDs
    if hasattr(self.rng, "getrandbits"):
        base = self.rng.getrandbits(64)
    else:
        # Deterministic fallback when self.rng has no getrandbits (e.g. a simple mock)
        base = (pred_i * 2654435761 + demo_set_i * 40503 + 0x9E3779B97F4A7C15) & 0xFFFFFFFFFFFFFFFF
    n = base ^ ((pred_i & 0xFFFF) << 16) ^ (demo_set_i & 0xFFFF)
    # Base32 (no padding) for compact ASCII salt
    alphabet = "ABCDEFGHIJKLMNOPQRSTUVWXYZ234567"
    out = []
    x = n
    for _ in range(13):  # 13*5=65 bits coverage
        out.append(alphabet[x & 31]); x >>= 5
    return "".join(out)

def _truncate_description_at_sentence_boundary(self, description: str, max_chars: int) -> str:
    if max_chars is None or len(description) < max_chars:
        return description

    # Reserve room so the final string (including the ellipsis) is strictly shorter than max_chars.
    search_limit = max_chars - 2
    boundaries = (". ", "! ", "? ")
    best_end = -1
    for boundary in boundaries:
        idx = description.rfind(boundary, 0, search_limit)
        if idx != -1:
            end = idx + len(boundary)
            best_end = max(best_end, end)

    if best_end == -1:
        return description[:max_chars - 2] + "…"

    return description[:best_end] + "…"

